import { NextRequest, NextResponse } from "next/server";
import fs from 'fs/promises';

export async function POST(request: NextRequest) {
    const files = await request.formData();

    const contextFiles = files.getAll("contextFiles");
    const templateFile = files.get("templateFile");    
    // -------------------------
    // Handle template file
    // -------------------------
    if (templateFile instanceof File) {
        const arrayBuffer = await templateFile.arrayBuffer();
        const buffer = Buffer.from(arrayBuffer);

        const templateDir = "uploaded_files/template";
        await fs.mkdir(templateDir, { recursive: true });

        await fs.writeFile(`${templateDir}/${templateFile.name}`, buffer);
        console.log("Template file uploaded")
    }

    // -------------------------
    // Handle context files
    // -------------------------
    if (contextFiles.length > 0) {
        const contextDir = "uploaded_files/context";
        await fs.mkdir(contextDir, { recursive: true });

        for (const f of contextFiles) {
            if (f instanceof File) {
                const arrayBuffer = await f.arrayBuffer();
                const buffer = Buffer.from(arrayBuffer);

                await fs.writeFile(`${contextDir}/${f.name}`, buffer);
            }
        }
        console.log("Context files uploaded")
    }

    return NextResponse.json({ message: "Files saved successfully!" });
}